## getopts Şablonu
```bash
usage() { echo "Kullanım: $0 [-e ortam] [-d] [-h]"; exit 1; }

DEBUG=false ENV=prod
while getopts ':e:dh' opt; do
    case $opt in
        e) ENV="$OPTARG" ;;
        d) DEBUG=true ;;
        h) usage ;;
        :) echo "$OPTARG argüman gerektirir"; usage ;;
        \?) echo "Bilinmeyen: -$OPTARG"; usage ;;
    esac
done
shift $((OPTIND-1))

$DEBUG && set -x  # Debug modu
echo "Ortam: $ENV"
```
